UPDATE TBL_BOARD_FILE
   SET IS_THUMBNAIL = 'Y',
       UPDATED_AT   = SYSDATE
 WHERE BOARD_ID     = #{boardId}
   AND FILE_ID      = #{fileId}
   AND IS_ACTIVE    = 'Y'

UPDATE TBL_BOARD
   SET IS_ACTIVE   = 'N',
       UPDATE_DATE = SYSDATE
 WHERE BOARD_ID    = #{boardId}
   AND USER_ID     = #{loginUserId}
   AND IS_ACTIVE   = 'Y'

